script.text:

function active$Voucher$(f) {
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$ReferenceKeyFilter(f);
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {set$Voucher$ReferenceKeyFilter(f);}
function close$Voucher$(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
/* <flatten type="Javascript"> */
function set$Voucher$ReferenceKeyFilter(f) {
  var v = f.getItemValue('nhieu_dvt');
  if(v) f.setReferenceKeyFilter('dvt');
  if (f._action != 'View') f._setReadOnly(f.getItem('dvt'), !v);
}
/* </flatten> */
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('ddm')._controlBehavior;
  switch (action) {
    case 'Check':
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function onChange$Voucher$Product(o) {o.parentForm.request('Product', 'Product', ['ma_sp'], o);}
function onChange$Voucher$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ddm'&ListTabChange;&PostTabChange;]);&PostTabFocus;}
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Product':
      f.setItemControlBehavior('dvt', result[0].Value, null, false);
      f.setItemValue('nhieu_dvt', result[1].Value);
      set$Voucher$ReferenceKeyFilter(f);
      break;
    case 'Scattering':
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &ListResponseTicket;

    default:
      break;
  }
}

